#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream inputFile("text.txt");
    std::string targetWord = "specific";
    std::string line;
    int count = 0;

    if (inputFile.is_open()) {
        while (getline(inputFile, line)) {
            size_t pos = line.find(targetWord);
            while (pos != std::string::npos) {
                count++;
                pos = line.find(targetWord, pos + 1);
            }
